def validate_cart_items(cart_items: List[CartItem]) -> Dict[str, Any]:
    if not cart_items:
        raise ValidationError("Cart is empty.")

    normalized_items = []
    subtotal = Decimal("0.00")
    for item in cart_items:
        if not item.sku or not item.name:
            raise ValidationError("Each cart item must have a sku and name.")
        if item.quantity <= 0:
            raise ValidationError(f"Invalid quantity for item {item.sku}.")
        if item.unit_price < 0:
            raise ValidationError(f"Invalid unit price for item {item.sku}.")
        line_total = item.line_total()
        subtotal += line_total
        normalized_items.append(
            {
                "sku": item.sku,
                "name": item.name,
                "unit_price": money(item.unit_price),
                "quantity": item.quantity,
                "taxable": item.taxable,
                "line_total": money(line_total),
            }
        )

    return {"items": normalized_items, "subtotal": money(subtotal)}


def _validate_discount_permission(user: User, discount: DiscountCode) -> None:
    if discount.admin_only and not user.is_admin:
        raise PermissionError(f"Discount code {discount.code} is admin-only.")
    if discount.allowed_tiers is not None and user.tier not in discount.allowed_tiers:
        raise PermissionError(f"Discount code {discount.code} is not allowed for tier {user.tier}.")


def apply_discount_codes(user: User, cart_state: Dict[str, Any], discount_codes: List[DiscountCode]) -> Dict[str, Any]:
    subtotal = money(cart_state["subtotal"])
    items = cart_state["items"]

    discount_total = Decimal("0.00")
    applied_codes = []
    current_subtotal = subtotal

    for discount in discount_codes:
        _validate_discount_permission(user, discount)

        if discount.min_subtotal is not None and subtotal < money(discount.min_subtotal):
            raise ValidationError(f"Discount code {discount.code} requires a minimum subtotal of {discount.min_subtotal}.")

        if discount.kind == "percent":
            amount = current_subtotal * (money(discount.value) / Decimal("100"))
        elif discount.kind == "fixed":
            amount = money(discount.value)
        else:
            raise ValidationError(f"Unknown discount type for code {discount.code}.")

        if discount.max_discount is not None:
            amount = min(money(amount), money(discount.max_discount))

        amount = max(Decimal("0.00"), money(amount))
        amount = min(amount, current_subtotal)

        current_subtotal -= amount
        discount_total += amount
        applied_codes.append(discount.code)

    return {
        "items": items,
        "subtotal": subtotal,
        "discount_total": money(discount_total),
        "discounted_subtotal": money(current_subtotal),
        "applied_discount_codes": applied_codes,
    }


def calculate_tax(checkout_state: Dict[str, Any], tax_rate: Decimal) -> Dict[str, Any]:
    discounted_subtotal = money(checkout_state["discounted_subtotal"])
    items = checkout_state["items"]

    taxable_amount = Decimal("0.00")
    subtotal_before_discounts = Decimal("0.00")

    for item in items:
        line_total = money(item["line_total"])
        subtotal_before_discounts += line_total
        if item["taxable"]:
            taxable_amount += line_total

    if subtotal_before_discounts > 0:
        taxable_ratio = taxable_amount / subtotal_before_discounts
    else:
        taxable_ratio = Decimal("0.00")

    taxable_after_discounts = discounted_subtotal * taxable_ratio
    tax = taxable_after_discounts * money(tax_rate) / Decimal("100")

    return {
        **checkout_state,
        "taxable_amount": money(taxable_amount),
        "tax": money(tax),
        "total": money(discounted_subtotal + tax),
    }


def process_payment(user: User, amount: Decimal, payment_method: Dict[str, Any]) -> PaymentResult:
    if amount <= 0:
        return PaymentResult(success=False, error="Payment amount must be positive.")

    if not payment_method.get("token"):
        return PaymentResult(success=False, error="Missing payment token.")

    transaction_id = str(uuid.uuid4())
    return PaymentResult(success=True, transaction_id=transaction_id)


def create_order_record(user: User, checkout_state: Dict[str, Any], payment_result: PaymentResult) -> OrderRecord:
    if not payment_result.success or not payment_result.transaction_id:
        raise PaymentError(payment_result.error or "Payment failed.")

    return OrderRecord(
        order_id=str(uuid.uuid4()),
        user_id=user.user_id,
        items=checkout_state["items"],
        subtotal=money(checkout_state["subtotal"]),
        discount_total=money(checkout_state["discount_total"]),
        tax=money(checkout_state["tax"]),
        total=money(checkout_state["total"]),
        payment_transaction_id=payment_result.transaction_id,
        applied_discount_codes=list(checkout_state.get("applied_discount_codes", [])),
    )


def checkout(
    user: User,
    cart_items: List[CartItem],
    discount_codes: Optional[List[DiscountCode]] = None,
    tax_rate: Decimal = Decimal("0"),
    payment_method: Optional[Dict[str, Any]] = None,
) -> OrderRecord:
    discount_codes = discount_codes or []
    payment_method = payment_method or {}

    cart_state = validate_cart_items(cart_items)
    discount_state = apply_discount_codes(user, cart_state, discount_codes)
    tax_state = calculate_tax(discount_state, tax_rate)
    payment_result = process_payment(user, tax_state["total"], payment_method)
    if not payment_result.success:
        raise PaymentError(payment_result.error or "Payment failed.")
    return create_order_record(user, tax_state, payment_result)